// packages/adapters/src/tmux-runner.ts
function defaultTmuxRunner() {
  return {
    async run(args) {
      const proc = Bun.spawn(["tmux", ...args], {
        stdout: "pipe",
        stderr: "pipe"
      });
      const exitCode = await proc.exited;
      const stdout = await new Response(proc.stdout).text();
      const stderr = await new Response(proc.stderr).text();
      return { stdout, stderr, exitCode };
    }
  };
}

// packages/adapters/src/pane-backend.ts
class PaneBackend {
  runner;
  sendKeysDelayMs;
  constructor(options = {}) {
    this.runner = options.runner ?? defaultTmuxRunner();
    this.sendKeysDelayMs = options.sendKeysDelayMs ?? 200;
  }
  sessionNameFor(task_id) {
    return `cuekit-task-${task_id}`;
  }
  computeAttachHint(task_id) {
    return `tmux attach-session -t ${this.sessionNameFor(task_id)}`;
  }
  async spawnTask(params) {
    const sessionName = this.sessionNameFor(params.task_id);
    const envArgs = Object.entries(params.env ?? {}).flatMap(([key, value]) => {
      if (!/^[A-Za-z_][A-Za-z0-9_]*$/.test(key)) {
        throw new Error(`invalid tmux environment key '${key}'`);
      }
      return ["-e", `${key}=${value}`];
    });
    const result = await this.runner.run([
      "new-session",
      "-d",
      "-s",
      sessionName,
      ...envArgs,
      "-c",
      params.cwd,
      "-P",
      "-F",
      "#{pane_id}",
      params.launchCommand
    ]);
    if (result.exitCode !== 0) {
      throw new Error(`tmux new-session for task ${params.task_id} failed (exit ${result.exitCode}): ${result.stderr.trim()}`);
    }
    const pane_id = result.stdout.trim();
    if (!pane_id) {
      throw new Error(`tmux new-session for task ${params.task_id} did not report a pane id`);
    }
    if (params.transcriptPath) {
      const pipeResult = await this.runner.run([
        "pipe-pane",
        "-t",
        pane_id,
        "-o",
        `cat > ${shellQuote(params.transcriptPath)}`
      ]);
      if (pipeResult.exitCode !== 0) {
        try {
          await this.killTask(params.task_id);
        } catch {}
        throw new Error(`tmux pipe-pane for task ${params.task_id} failed: ${pipeResult.stderr.trim()}`);
      }
    }
    return {
      task_id: params.task_id,
      tmux_session_name: sessionName,
      pane_id,
      attach_hint: this.computeAttachHint(params.task_id)
    };
  }
  async isAlive(task_id) {
    const result = await this.runner.run(["has-session", "-t", this.sessionNameFor(task_id)]);
    return result.exitCode === 0;
  }
  async sendKeys(task_id, message) {
    const target = this.sessionNameFor(task_id);
    const literal2 = await this.runner.run(["send-keys", "-t", target, "-l", message]);
    if (literal2.exitCode !== 0) {
      throw new Error(`tmux send-keys -l for task ${task_id} failed: ${literal2.stderr.trim()}`);
    }
    if (this.sendKeysDelayMs > 0) {
      await Bun.sleep(this.sendKeysDelayMs);
    }
    const enter = await this.runner.run(["send-keys", "-t", target, "Enter"]);
    if (enter.exitCode !== 0) {
      throw new Error(`tmux send-keys Enter for task ${task_id} failed: ${enter.stderr.trim()}`);
    }
  }
  async killTask(task_id) {
    const result = await this.runner.run(["kill-session", "-t", this.sessionNameFor(task_id)]);
    if (result.exitCode !== 0 && !/can't find session|session not found|no such session|no server running/i.test(result.stderr)) {
      throw new Error(`tmux kill-session for task ${task_id} failed: ${result.stderr.trim()}`);
    }
  }
}
